      "role": "user",
      "content": "Ticket input:\nticketId: {{$json.body.ticketId}}\nfirstName: {{$json.body.firstName}}\nlastName: {{$json.body.lastName}}\nemail: {{$json.body.email}}\nmessage: {{$json.body.message}}"
