parameters.jsCode:
const body = $('Webhook').first().json.body || {};

const validSentiments = new Set(['frustrated', 'neutral', 'happy']);
const validCategories = new Set(['technical', 'billing', 'feedback', 'other']);
const validPriorities = new Set(['low', 'medium', 'high']);
const fallbackDraft = 'Thank you for contacting SupportIQ. We received your ticket and a support agent will follow up shortly.';

const payload =
  $json?.body && typeof $json.body === 'object'
    ? $json.body
    : $json;

const hasGroqChoice = Boolean(payload?.choices?.[0]?.message?.content);
const hasGeminiCandidate = Boolean(payload?.candidates?.[0]?.content?.parts?.[0]?.text);
const hasCandidate = hasGroqChoice || hasGeminiCandidate;

let upstreamError =
  payload?.error?.message ||
  payload?.message ||
  (Array.isArray(payload?.errors) && payload.errors[0]?.message) ||
  $json?.error?.message ||
  $json?.message ||
  (Array.isArray($json?.errors) && $json.errors[0]?.message) ||
  null;

let raw = hasGroqChoice
  ? (payload.choices?.[0]?.message?.content ?? '{}')
  : hasGeminiCandidate
    ? (payload.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}')
    : '{}';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw ?? {});
}
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

let parseFailed = false;
let parsed = {};

if (!upstreamError) {
  try {
    parsed = JSON.parse(raw || '{}');
  } catch {
    parseFailed = true;
    parsed = {};
  }
} else {
  parseFailed = true;
}

if (!upstreamError && !hasCandidate) {
  const finishReason = payload?.choices?.[0]?.finish_reason || null;
  upstreamError = finishReason
    ? `AI returned empty content (finish_reason: ${finishReason}).`
    : 'AI returned no candidate content.';
}

if (!upstreamError && parseFailed) {
  upstreamError = 'Invalid AI JSON output.';
}

const sentiment = typeof parsed.sentiment === 'string' ? parsed.sentiment.toLowerCase().trim() : 'neutral';
const category = typeof parsed.category === 'string' ? parsed.category.toLowerCase().trim() : 'other';
const priority = typeof parsed.priority === 'string' ? parsed.priority.toLowerCase().trim() : 'medium';

const normalizedSentiment = validSentiments.has(sentiment) ? sentiment : 'neutral';
const normalizedCategory = validCategories.has(category) ? category : 'other';
const normalizedPriority = validPriorities.has(priority) ? priority : 'medium';

const confidenceRaw = Number(parsed.confidence);
const confidence = Number.isFinite(confidenceRaw)
  ? Math.max(0, Math.min(100, Math.round(confidenceRaw)))
  : 0;
const draft_response = typeof parsed.draft_response === 'string' && parsed.draft_response.trim()
  ? parsed.draft_response.trim()
  : fallbackDraft;

const needsHuman =
  Boolean(upstreamError) ||
  normalizedPriority === 'high' ||
  confidence < 85 ||
  normalizedCategory === 'billing';

return [
  {
    json: {
      ticket_id: body.ticketId || null,
      first_name: body.firstName || '',
      last_name: body.lastName || '',
      email: body.email || '',
      message: body.message || '',
      sentiment: normalizedSentiment,
      category: normalizedCategory,
      priority: normalizedPriority,
      confidence,
      draft_response,
      parse_failed: parseFailed,
      route_action: needsHuman ? 'needs_human' : 'auto_send',
      status: needsHuman ? 'needs_human' : 'ai_ready',
      auto_sent: false,
      responded_at: null,
      final_response: null,
      email_error: null,
      ai_error: upstreamError,
      raw_model_output: raw
    }
  }
];

const analysis = $items('Build AI Analysis + Policy', 0, 0)?.[0]?.json || {};
const emailResult = $json ?? null;

const asString = typeof emailResult === 'string'
  ? emailResult
  : (typeof emailResult?.body === 'string' ? emailResult.body : '');

const statusCodeRaw = Number(
  emailResult?.statusCode ??
  emailResult?.status ??
  emailResult?.code ??
  NaN
);
const statusCode = Number.isFinite(statusCodeRaw) ? statusCodeRaw : null;

const explicitError =
  emailResult?.error?.message ||
  emailResult?.error ||
  emailResult?.message ||
  null;

const normalizedBody = asString.trim().toLowerCase();
const bodyLooksOk = normalizedBody === 'ok' || normalizedBody === 'success';
const has2xx = statusCode !== null && statusCode >= 200 && statusCode < 300;
const explicitSuccess =
  emailResult?.ok === true ||
  emailResult?.success === true ||
  emailResult?.status === 'OK' ||
  emailResult?.statusText === 'OK';

// n8n HTTP Request with continueOnFail usually exposes explicit error details on failure.
// If we have no explicit error, treat it as success to avoid false negatives from body shape differences.
const hasAnyErrorSignal = Boolean(explicitError) || (statusCode !== null && statusCode >= 400);
const isSuccess = !hasAnyErrorSignal || bodyLooksOk || has2xx || explicitSuccess;

if (!isSuccess) {
  const fallbackError =
    explicitError ||
    (statusCode !== null ? `Email send failed (${statusCode})` : null) ||
    (asString ? `Email send failed (${asString.slice(0, 140)})` : null) ||
    'Email send failed: no success acknowledgment from EmailJS.';

  return [
    {
      json: {
        ...analysis,
        route_action: 'needs_human',
        status: 'needs_human',
        auto_sent: false,
        responded_at: null,
        final_response: null,
        email_error: fallbackError
      }
    }
  ];
}

return [
  {
    json: {
      ...analysis,
      route_action: 'auto_send',
      status: 'responded',
      auto_sent: true,
      responded_at: new Date().toISOString(),
      final_response: analysis.draft_response || '',
      email_error: null
    }
  }
];

const analysis = $json || {};
return [
  {
    json: {
      ...analysis,
      route_action: 'needs_human',
      status: 'needs_human',
      auto_sent: false,
      responded_at: null,
      final_response: null,
      email_error: analysis.email_error || null
    }
  }
];
